     7→
     8→import React, { useState, useRef, useCallback, useEffect, useMemo } from 'react';
     9→import { LexicalComposer } from '@lexical/react/LexicalComposer';
    10→import { RichTextPlugin } from '@lexical/react/LexicalRichTextPlugin';
    11→import { ContentEditable } from '@lexical/react/LexicalContentEditable';
    12→import { HistoryPlugin } from '@lexical/react/LexicalHistoryPlugin';
    13→import { OnChangePlugin } from '@lexical/react/LexicalOnChangePlugin';
    14→import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
    15→import { LexicalErrorBoundary } from '@lexical/react/LexicalErrorBoundary';
    16→import { HeadingNode, QuoteNode } from '@lexical/rich-text';
    17→import { ListNode, ListItemNode } from '@lexical/list';
    18→import { CodeNode, CodeHighlightNode } from '@lexical/code';
    19→import { LinkNode } from '@lexical/link';
    20→import { TableNode, TableCellNode, TableRowNode } from '@lexical/table';
    21→import { ListPlugin } from '@lexical/react/LexicalListPlugin';
    22→import { TablePlugin } from '@lexical/react/LexicalTablePlugin';
    23→import { MarkdownShortcutPlugin } from '@lexical/react/LexicalMarkdownShortcutPlugin';
    24→import { AutoLinkPlugin } from '@lexical/react/LexicalAutoLinkPlugin';
    25→import { AutoLinkNode } from '@lexical/link';
    26→import { TRANSFORMERS } from '@lexical/markdown';
    27→import {
    28→  $getRoot,
    29→  $getSelection,
    30→  FORMAT_TEXT_COMMAND,
    31→  $isRangeSelection,
    32→  $createParagraphNode,
    33→  UNDO_COMMAND,
    34→  REDO_COMMAND,
    35→  $isParagraphNode
    36→} from 'lexical';
    37→import type { EditorState } from 'lexical';
    38→import {
    39→  registerRichText,
    40→  $createHeadingNode,
    41→  $createQuoteNode,
    42→  $isHeadingNode,
    43→  $isQuoteNode
    44→} from '@lexical/rich-text';
    45→import type { HeadingTagType } from '@lexical/rich-text';
