    50→} from '@lexical/list';
    51→
    52→// URL matcher for AutoLinkPlugin
    53→const URL_MATCHER =
    54→  /((https?:\/\/(www\.)?)|(www\.))[-a-zA-Z0-9@:%._+~#=]{1,256}\.[a-zA-Z0-9()]{1,6}\b([-a-zA-Z0-9()@:%_+.~#?&//=]*)/;
    55→
    56→const MATCHERS = [
    57→  (text: string) => {
    58→    const match = URL_MATCHER.exec(text);
    59→    if (match === null) {
    60→      return null;
    61→    }
    62→    const fullMatch = match[0];
    63→    return {
    64→      index: match.index,
    65→      length: fullMatch.length,
    66→      text: fullMatch,
    67→      url: fullMatch.startsWith('http') ? fullMatch : `https://${fullMatch}`,
    68→    };
    69→  },
    70→];
    71→import { motion } from 'framer-motion';
    72→import { useNotesStore } from '../stores/useNotesStore';
    73→import { useSettingsStore } from '../stores/useSettingsStore';
    74→import { TagPicker } from '../components/TagPicker';
    75→import { CustomFieldEditor } from '../components/CustomFieldEditor';
    76→import { NOTE_CONSTANTS } from '../types/notes';
    77→import { ImageNode, $createImageNode } from './NotesEditor/ImageNode';
    78→import { indexedDBService } from '../services/indexedDB';
    79→import { BacklinksPanel } from '../components/BacklinksPanel';
    80→import { toast } from '../stores/useToastStore';
    81→import WikiLinkAutocompletePlugin from '../components/editor/WikiLinkAutocompletePlugin';
    82→import WikiLinkTransformPlugin from '../components/editor/WikiLinkTransformPlugin';
    83→import HoverPreviewPlugin from '../components/editor/plugins/HoverPreviewPlugin';
    84→import BlockReferencePlugin from '../components/editor/plugins/BlockReferencePlugin';
    85→import HashtagPlugin from '../components/editor/plugins/HashtagPlugin';
    86→import { WikiLinkNode } from '../components/editor/WikiLinkNode';
    87→import { HashtagNode } from '../components/editor/nodes/HashtagNode';
    88→
    89→/**
    90→ * Keyboard Shortcuts Plugin
    91→ * Registers rich text keyboard shortcuts (Cmd+B, Cmd+I, Cmd+U)
    92→ */
    93→const KeyboardShortcutsPlugin: React.FC = () => {
    94→  const [editor] = useLexicalComposerContext();
    95→
    96→  useEffect(() => {
    97→    return registerRichText(editor);
    98→  }, [editor]);
    99→
   100→  return null;
   101→};
   102→
   103→/**
   104→ * Word Count Plugin
   105→ * Tracks word and character count from editor content
   106→ */
   107→const WordCountPlugin: React.FC<{ onUpdate: (words: number, chars: number) => void }> = ({ onUpdate }) => {
   108→  const [editor] = useLexicalComposerContext();
   109→
   110→  useEffect(() => {
   111→    return editor.registerTextContentListener((textContent) => {
   112→      const words = textContent.trim().split(/\s+/).filter(Boolean).length;
   113→      const chars = textContent.length;
   114→      onUpdate(words, chars);
   115→    });
   116→  }, [editor, onUpdate]);
   117→
   118→  return null;
   119→};
   120→
   121→/**
   122→ * Image Upload Plugin
   123→ * Handles drag-and-drop and paste events for images
   124→ */
   125→const ImageUploadPlugin: React.FC<{ noteId: string }> = ({ noteId }) => {
   126→  const [editor] = useLexicalComposerContext();
   127→  const [isDragging, setIsDragging] = useState(false);
   128→
   129→  const uploadImage = useCallback(async (file: File) => {
   130→    try {
   131→      // Store image in IndexedDB with compression
   132→      const imageId = await indexedDBService.storeImage(noteId, file);
   133→
   134→      // Retrieve compressed blob
   135→      const blob = await indexedDBService.getImage(imageId);
   136→      if (!blob) {
   137→        console.error('Failed to retrieve stored image');
   138→        return;
   139→      }
   140→
   141→      // Create blob URL for rendering
   142→      const blobUrl = URL.createObjectURL(blob);
   143→
   144→      // Insert image node into editor
   145→      editor.update(() => {
   146→        const selection = $getSelection();
   147→        if ($isRangeSelection(selection)) {
   148→          const imageNode = $createImageNode({
   149→            altText: file.name,
   150→            src: blobUrl,
   151→            imageId: imageId,
   152→          });
   153→          selection.insertNodes([imageNode]);
   154→        }
   155→      });
   156→
   157→      console.log(`✅ Image uploaded: ${imageId} (${file.name})`);
   158→    } catch (error) {
   159→      console.error('Failed to upload image:', error);
   160→    }
   161→  }, [editor, noteId]);
   162→
   163→  useEffect(() => {
   164→    const editorElement = editor.getRootElement();
   165→    if (!editorElement) return;
   166→
   167→    // Drag and drop handlers
   168→    const handleDragEnter = (e: DragEvent) => {
   169→      e.preventDefault();
   170→      e.stopPropagation();
   171→      if (e.dataTransfer?.types.includes('Files')) {
   172→        setIsDragging(true);
   173→      }
   174→    };
   175→
   176→    const handleDragOver = (e: DragEvent) => {
   177→      e.preventDefault();
   178→      e.stopPropagation();
   179→    };
   180→
   181→    const handleDragLeave = (e: DragEvent) => {
   182→      e.preventDefault();
   183→      e.stopPropagation();
   184→      // Only hide if leaving the editor entirely
   185→      if (e.target === editorElement) {
   186→        setIsDragging(false);
   187→      }
   188→    };
   189→
   190→    const handleDrop = async (e: DragEvent) => {
   191→      e.preventDefault();
   192→      e.stopPropagation();
   193→      setIsDragging(false);
   194→
   195→      const files = Array.from(e.dataTransfer?.files || []);
   196→      const imageFiles = files.filter(file => file.type.startsWith('image/'));
   197→
   198→      for (const file of imageFiles) {
   199→        await uploadImage(file);
   200→      }
   201→    };
   202→
   203→    // Paste handler
   204→    const handlePaste = async (e: ClipboardEvent) => {
   205→      const items = Array.from(e.clipboardData?.items || []);
   206→      const imageItems = items.filter(item => item.type.startsWith('image/'));
   207→
   208→      if (imageItems.length > 0) {
   209→        e.preventDefault();
   210→
   211→        for (const item of imageItems) {
   212→          const file = item.getAsFile();
   213→          if (file) {
   214→            await uploadImage(file);
   215→          }
   216→        }
   217→      }
   218→    };
   219→
   220→    editorElement.addEventListener('dragenter', handleDragEnter);
   221→    editorElement.addEventListener('dragover', handleDragOver);
   222→    editorElement.addEventListener('dragleave', handleDragLeave);
   223→    editorElement.addEventListener('drop', handleDrop);
   224→    editorElement.addEventListener('paste', handlePaste);
   225→
   226→    return () => {
   227→      editorElement.removeEventListener('dragenter', handleDragEnter);
   228→      editorElement.removeEventListener('dragover', handleDragOver);
   229→      editorElement.removeEventListener('dragleave', handleDragLeave);
   230→      editorElement.removeEventListener('drop', handleDrop);
   231→      editorElement.removeEventListener('paste', handlePaste);
   232→    };
   233→  }, [editor, uploadImage]);
   234→
   235→  // Drag overlay
   236→  if (isDragging) {
   237→    return (
   238→      <div className="absolute inset-0 z-50 bg-accent-blue/10 border-2 border-dashed border-accent-blue rounded-lg flex items-center justify-center pointer-events-none">
   239→        <div className="bg-surface-light dark:bg-surface-dark px-6 py-4 rounded-lg shadow-elevated">
   240→          <p className="text-accent-blue text-lg font-semibold">Drop image here</p>
   241→        </div>
   242→      </div>
   243→    );
   244→  }
   245→
   246→  return null;
   247→};
   248→
   249→/**
   250→ * Slash Command Plugin
   251→ * Detects '/' and shows command menu
   252→ */
   253→const SlashCommandPlugin: React.FC = () => {
   254→  const [editor] = useLexicalComposerContext();
   255→  const [showMenu, setShowMenu] = useState(false);
   256→  const [query, setQuery] = useState('');
   257→  const [menuPosition, setMenuPosition] = useState({ top: 0, left: 0 });
   258→
   259→  const commands = [
   260→    { label: 'Heading 1', icon: 'H1', action: () => {
   261→      editor.update(() => {
   262→        const selection = $getSelection();
   263→        if (selection) {
   264→          // Convert to heading - will implement with format commands
   265→          console.log('Heading 1');
   266→        }
   267→      });
   268→    }},
   269→    { label: 'Heading 2', icon: 'H2', action: () => console.log('Heading 2') },
   270→    { label: 'Heading 3', icon: 'H3', action: () => console.log('Heading 3') },
   271→    { label: 'Bullet List', icon: '•', action: () => console.log('Bullet List') },
   272→    { label: 'Numbered List', icon: '1.', action: () => console.log('Numbered List') },
   273→    { label: 'Code Block', icon: '</>', action: () => console.log('Code Block') },
   274→    { label: 'Quote', icon: '"', action: () => console.log('Quote') },
   275→  ];
   276→
   277→  const filteredCommands = commands.filter(cmd =>
   278→    cmd.label.toLowerCase().includes(query.toLowerCase())
   279→  );
   280→
   281→  useEffect(() => {
   282→    return editor.registerUpdateListener(({ editorState }) => {
   283→      editorState.read(() => {
   284→        const selection = $getSelection();
   285→        if (!selection) {
   286→          setShowMenu(false);
   287→          return;
   288→        }
   289→
   290→        const text = selection.getTextContent();
   291→        if (text.startsWith('/')) {
   292→          setQuery(text.slice(1));
   293→          setShowMenu(true);
   294→
   295→          // Get cursor position for menu placement
   296→          const nativeSelection = window.getSelection();
   297→          if (nativeSelection && nativeSelection.rangeCount > 0) {
   298→            const range = nativeSelection.getRangeAt(0);
   299→            const rect = range.getBoundingClientRect();
   300→            setMenuPosition({
   301→              top: rect.bottom + window.scrollY + 5,
   302→              left: rect.left + window.scrollX,
   303→            });
   304→          }
   305→        } else {
   306→          setShowMenu(false);
   307→        }
   308→      });
   309→    });
   310→  }, [editor]);
   311→
   312→  if (!showMenu || filteredCommands.length === 0) {
   313→    return null;
   314→  }
   315→
   316→  return (
   317→    <div
   318→      style={{
   319→        position: 'absolute',
   320→        top: `${menuPosition.top}px`,
   321→        left: `${menuPosition.left}px`,
   322→        zIndex: 1000,
   323→      }}
   324→      className="bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-lg shadow-lg py-2 min-w-[200px]"
   325→    >
   326→      {filteredCommands.map((cmd, index) => (
   327→        <button
   328→          key={index}
   329→          onClick={() => {
   330→            cmd.action();
   331→            setShowMenu(false);
   332→          }}
   333→          className="w-full px-4 py-2 text-left hover:bg-surface-light dark:hover:bg-surface-dark-elevated transition-colors flex items-center gap-3"
   334→        >
   335→          <span className="text-text-light-secondary dark:text-text-dark-secondary font-mono">
   336→            {cmd.icon}
   337→          </span>
   338→          <span className="text-text-light-primary dark:text-text-dark-primary">
   339→            {cmd.label}
   340→          </span>
   341→        </button>
   342→      ))}
   343→    </div>
   344→  );
   345→};
   346→
   347→/**
   348→ * View Mode Type
   349→ */
   350→type ViewMode = 'edit' | 'preview';
   351→
   352→/**
   353→ * Editor Toolbar Component
   354→ */
   355→const EditorToolbar: React.FC<{
   356→  wordCount: number;
   357→  charCount: number;
   358→  noteId: string;
   359→  viewMode: ViewMode;
   360→  onViewModeChange: (mode: ViewMode) => void;
   361→}> = ({ wordCount, charCount, noteId, viewMode, onViewModeChange }) => {
   362→  const [editor] = useLexicalComposerContext();
   363→  const fileInputRef = useRef<HTMLInputElement>(null);
   364→
   365→  const formatText = (format: 'bold' | 'italic' | 'underline' | 'strikethrough' | 'code') => {
   366→    editor.dispatchCommand(FORMAT_TEXT_COMMAND, format);
   367→  };
   368→
   369→  const formatHeading = (headingSize: HeadingTagType) => {
   370→    editor.update(() => {
   371→      const selection = $getSelection();
   372→      if ($isRangeSelection(selection)) {
   373→        const anchorNode = selection.anchor.getNode();
   374→        const element = anchorNode.getKey() === 'root'
   375→          ? anchorNode
   376→          : anchorNode.getTopLevelElementOrThrow();
   377→
   378→        if ($isHeadingNode(element) && element.getTag() === headingSize) {
   379→          // If already this heading, convert to paragraph
   380→          const paragraph = $createParagraphNode();
   381→          element.replace(paragraph, true);
   382→        } else {
   383→          // Convert to heading
   384→          const heading = $createHeadingNode(headingSize);
   385→          element.replace(heading, true);
   386→        }
   387→      }
   388→    });
   389→  };
   390→
   391→  const formatParagraph = () => {
   392→    editor.update(() => {
   393→      const selection = $getSelection();
   394→      if ($isRangeSelection(selection)) {
   395→        const anchorNode = selection.anchor.getNode();
   396→        const element = anchorNode.getKey() === 'root'
   397→          ? anchorNode
   398→          : anchorNode.getTopLevelElementOrThrow();
   399→
   400→        if (!$isParagraphNode(element) && !$isListNode(element)) {
   401→          const paragraph = $createParagraphNode();
   402→          element.replace(paragraph, true);
   403→        }
   404→      }
   405→    });
   406→  };
   407→
   408→  const formatQuote = () => {
   409→    editor.update(() => {
   410→      const selection = $getSelection();
   411→      if ($isRangeSelection(selection)) {
   412→        const anchorNode = selection.anchor.getNode();
   413→        const element = anchorNode.getKey() === 'root'
   414→          ? anchorNode
   415→          : anchorNode.getTopLevelElementOrThrow();
   416→
   417→        if ($isQuoteNode(element)) {
   418→          // If already a quote, convert to paragraph
   419→          const paragraph = $createParagraphNode();
   420→          element.replace(paragraph, true);
   421→        } else if (!$isListNode(element)) {
   422→          const quote = $createQuoteNode();
   423→          element.replace(quote, true);
   424→        }
   425→      }
   426→    });
   427→  };
   428→
   429→  const formatBulletList = () => {
   430→    editor.dispatchCommand(INSERT_UNORDERED_LIST_COMMAND, undefined);
   431→  };
   432→
   433→  const formatNumberedList = () => {
   434→    editor.dispatchCommand(INSERT_ORDERED_LIST_COMMAND, undefined);
   435→  };
   436→
   437→  const undo = () => {
   438→    editor.dispatchCommand(UNDO_COMMAND, undefined);
   439→  };
   440→
   441→  const redo = () => {
   442→    editor.dispatchCommand(REDO_COMMAND, undefined);
   443→  };
   444→
   445→  const handleImageUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
   446→    const file = event.target.files?.[0];
   447→    if (!file) return;
   448→
   449→    // Reset input immediately
   450→    if (fileInputRef.current) {
   451→      fileInputRef.current.value = '';
   452→    }
   453→
   454→    try {
   455→      // Store image in IndexedDB with compression
   456→      const imageId = await indexedDBService.storeImage(noteId, file);
   457→
   458→      // Retrieve compressed blob
   459→      const blob = await indexedDBService.getImage(imageId);
   460→      if (!blob) {
   461→        console.error('Failed to retrieve stored image');
   462→        return;
   463→      }
   464→
   465→      // Create blob URL for rendering
   466→      const blobUrl = URL.createObjectURL(blob);
   467→
   468→      // Insert image node into editor
   469→      editor.update(() => {
   470→        const selection = $getSelection();
   471→        if ($isRangeSelection(selection)) {
   472→          const imageNode = $createImageNode({
   473→            altText: file.name,
   474→            src: blobUrl,
   475→            imageId: imageId,
   476→          });
   477→          selection.insertNodes([imageNode]);
   478→        }
   479→      });
   480→
   481→      console.log(`✅ Image uploaded: ${imageId} (${file.name})`);
   482→    } catch (error) {
   483→      console.error('Failed to upload image:', error);
   484→      toast.error(
   485→        'Failed to upload image',
   486→        `${error instanceof Error ? error.message : 'Unknown error'}. Check file size (max 5MB) and storage quota.`
   487→      );
   488→    }
   489→  };
   490→
   491→  const btnClass = "p-2 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-all duration-standard text-text-light-primary dark:text-text-dark-primary";
   492→  const dividerClass = "w-px h-6 bg-border-light dark:bg-border-dark";
   493→
   494→  return (
   495→    <div className="border-b border-border-light dark:border-border-dark bg-surface-light dark:bg-surface-dark-elevated p-3 flex items-center gap-2 flex-wrap">
   496→      {/* Undo/Redo */}
   497→      <button onClick={undo} className={btnClass} title="Undo (Cmd+Z)">
   498→        ↶
   499→      </button>
   500→      <button onClick={redo} className={btnClass} title="Redo (Cmd+Shift+Z)">
   501→        ↷
   502→      </button>
   503→
   504→      <div className={dividerClass} />
   505→
   506→      {/* Text Format */}
   507→      <button onClick={() => formatText('bold')} className={btnClass} title="Bold (Cmd+B)">
   508→        <span className="font-bold">B</span>
   509→      </button>
   510→      <button onClick={() => formatText('italic')} className={btnClass} title="Italic (Cmd+I)">
   511→        <span className="italic">I</span>
   512→      </button>
   513→      <button onClick={() => formatText('underline')} className={btnClass} title="Underline (Cmd+U)">
   514→        <span className="underline">U</span>
   515→      </button>
   516→      <button onClick={() => formatText('strikethrough')} className={btnClass} title="Strikethrough">
   517→        <span className="line-through">S</span>
   518→      </button>
   519→      <button onClick={() => formatText('code')} className={btnClass} title="Code">
   520→        <span className="font-mono text-sm">&lt;/&gt;</span>
   521→      </button>
   522→
   523→      <div className={dividerClass} />
   524→
   525→      {/* Headings */}
   526→      <button onClick={() => formatHeading('h1')} className={btnClass} title="Heading 1">
   527→        <span className="font-bold text-lg">H1</span>
   528→      </button>
   529→      <button onClick={() => formatHeading('h2')} className={btnClass} title="Heading 2">
   530→        <span className="font-bold">H2</span>
   531→      </button>
   532→      <button onClick={() => formatHeading('h3')} className={btnClass} title="Heading 3">
   533→        <span className="font-bold text-sm">H3</span>
   534→      </button>
   535→      <button onClick={formatParagraph} className={btnClass} title="Paragraph">
   536→        <span className="text-sm">P</span>
   537→      </button>
   538→
   539→      <div className={dividerClass} />
   540→
   541→      {/* Lists */}
   542→      <button onClick={formatBulletList} className={btnClass} title="Bullet List">
   543→        ≡
   544→      </button>
   545→      <button onClick={formatNumberedList} className={btnClass} title="Numbered List">
   546→        ⋮
   547→      </button>
   548→      <button onClick={formatQuote} className={btnClass} title="Quote">
   549→        "
   550→      </button>
   551→
   552→      <div className={dividerClass} />
   553→
   554→      {/* Image Upload */}
   555→      <input
   556→        ref={fileInputRef}
   557→        type="file"
   558→        accept="image/*"
   559→        onChange={handleImageUpload}
   560→        className="hidden"
   561→      />
   562→      <button
   563→        onClick={() => fileInputRef.current?.click()}
   564→        className={btnClass}
   565→        title="Insert Image"
   566→      >
   567→        🖼️
   568→      </button>
   569→
   570→      <div className="flex-1" />
   571→
   572→      {/* View Mode Toggle */}
   573→      <div className="flex items-center gap-1 mr-4">
   574→        <button
   575→          onClick={() => onViewModeChange('edit')}
   576→          className={`px-2 py-1 text-xs rounded transition-all duration-standard ${
   577→            viewMode === 'edit'
   578→              ? 'bg-accent-cyan text-white'
   579→              : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   580→          }`}
   581→          title="Edit Mode (Cmd+E)"
   582→          aria-pressed={viewMode === 'edit'}
   583→        >
   584→          Edit
   585→        </button>
   586→        <button
   587→          onClick={() => onViewModeChange('preview')}
   588→          className={`px-2 py-1 text-xs rounded transition-all duration-standard ${
   589→            viewMode === 'preview'
   590→              ? 'bg-accent-cyan text-white'
   591→              : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   592→          }`}
   593→          title="Preview Mode (Cmd+E)"
   594→          aria-pressed={viewMode === 'preview'}
   595→        >
   596→          Preview
   597→        </button>
   598→      </div>
   599→
   600→      {/* Word count */}
   601→      <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
   602→        {wordCount} {wordCount === 1 ? 'word' : 'words'} · {charCount} {charCount === 1 ? 'char' : 'chars'}
   603→      </span>
   604→    </div>
   605→  );
   606→};
   607→
   608→/**
   609→ * Read-Only Mode Plugin
   610→ * Controls whether the editor is in read-only mode
   611→ */
   612→const ReadOnlyPlugin: React.FC<{ isReadOnly: boolean }> = ({ isReadOnly }) => {
   613→  const [editor] = useLexicalComposerContext();
   614→
   615→  useEffect(() => {
   616→    editor.setEditable(!isReadOnly);
   617→  }, [editor, isReadOnly]);
   618→
   619→  return null;
   620→};
   621→
   622→/**
   623→ * Auto-save Plugin
   624→ * Debounces editor changes and saves to store
   625→ */
   626→const AutoSavePlugin: React.FC<{ noteId: string }> = ({ noteId }) => {
   627→  const [isSaving, setIsSaving] = useState(false);
   628→  const updateNote = useNotesStore((state) => state.updateNote);
   629→
   630→  // Track timeout ID and last saved content to prevent redundant saves
   631→  const timeoutIdRef = useRef<ReturnType<typeof setTimeout> | null>(null);
   632→  const lastContentRef = useRef<string>('');
   633→  const lastTextRef = useRef<string>('');
   634→
   635→  const handleChange = useCallback((editorState: EditorState) => {
   636→    // Extract plain text for search
   637→    editorState.read(() => {
   638→      const root = $getRoot();
   639→      const contentText = root.getTextContent();
   640→      const contentJson = JSON.stringify(editorState.toJSON());
   641→
   642→      // Skip save if content hasn't actually changed
   643→      if (contentJson === lastContentRef.current && contentText === lastTextRef.current) {
   644→        return;
   645→      }
   646→
   647→      // Clear previous timeout to implement proper debouncing
   648→      if (timeoutIdRef.current) {
   649→        clearTimeout(timeoutIdRef.current);
   650→      }
   651→
   652→      // Debounced save with error handling
   653→      timeoutIdRef.current = setTimeout(() => {
   654→        setIsSaving(true);
   655→
   656→        try {
   657→          // Zustand is synchronous, but IndexedDB persistence could fail
   658→          updateNote(noteId, {
   659→            content: contentJson,
   660→            contentText,
   661→          });
   662→
   663→          // Update refs with saved content
   664→          lastContentRef.current = contentJson;
   665→          lastTextRef.current = contentText;
   666→
   667→          // Reset saving state after a brief delay
   668→          setTimeout(() => setIsSaving(false), 300);
   669→        } catch (error) {
   670→          console.error('❌ Failed to save note:', error);
   671→          setIsSaving(false);
   672→          // Error will be handled by IndexedDB quota monitoring system
   673→          // User will be alerted if quota is exceeded via Settings page
   674→        }
   675→      }, NOTE_CONSTANTS.AUTOSAVE_DEBOUNCE_MS);
   676→    });
   677→  }, [noteId, updateNote]);
   678→
   679→  // Cleanup timeout on unmount
   680→  useEffect(() => {
   681→    return () => {
   682→      if (timeoutIdRef.current) {
   683→        clearTimeout(timeoutIdRef.current);
   684→      }
   685→    };
   686→  }, []);
   687→
   688→  return (
   689→    <>
   690→      <OnChangePlugin onChange={handleChange} />
   691→      {isSaving && (
   692→        <div className="absolute top-2 right-2 text-xs text-text-light-secondary dark:text-text-dark-secondary">
   693→          Saving...
   694→        </div>
   695→      )}
   696→    </>
   697→  );
   698→};
   699→
   700→/**
   701→ * Lexical Editor Configuration
   702→ */
   703→const getEditorConfig = (initialContent?: string) => ({
   704→  namespace: 'NotesEditor',
   705→  editorState: initialContent || null,
   706→  theme: {
   707→    root: 'editor-root',
   708→    paragraph: 'editor-paragraph leading-relaxed', // 1.625 line-height for readability
   709→    text: {
   710→      bold: 'font-bold',
   711→      italic: 'italic',
   712→      underline: 'underline',
   713→      strikethrough: 'line-through',
   714→      code: 'font-mono bg-surface-light-elevated dark:bg-surface-dark-elevated px-1.5 py-0.5 rounded text-sm',
   715→    },
   716→    heading: {
   717→      h1: 'text-4xl font-bold mt-8 mb-4 leading-tight tracking-tight',
   718→      h2: 'text-3xl font-bold mt-6 mb-3 leading-snug',
   719→      h3: 'text-2xl font-semibold mt-5 mb-2 leading-normal',
   720→    },
   721→    list: {
   722→      ul: 'list-disc list-inside my-4 space-y-1.5',
   723→      ol: 'list-decimal list-inside my-4 space-y-1.5',
   724→      listitem: 'my-1 leading-relaxed',
   725→    },
   726→    quote: 'border-l-4 border-accent-cyan dark:border-accent-magenta bg-surface-light-elevated dark:bg-surface-dark-elevated pl-4 py-3 italic my-4 rounded-r',
   727→    code: 'bg-surface-dark dark:bg-surface-dark-elevated text-text-dark-primary p-4 rounded-lg font-mono text-sm my-4 overflow-x-auto shadow-sm',
   728→    link: 'text-accent-cyan dark:text-accent-magenta hover:underline transition-colors',
   729→  },
   730→  nodes: [
   731→    HeadingNode,
   732→    QuoteNode,
   733→    ListNode,
   734→    ListItemNode,
   735→    CodeNode,
   736→    CodeHighlightNode,
   737→    LinkNode,
   738→    AutoLinkNode,
   739→    TableNode,
   740→    TableCellNode,
   741→    TableRowNode,
   742→    ImageNode,
   743→    WikiLinkNode,
   744→    HashtagNode,
   745→  ],
   746→  onError: (error: Error) => {
   747→    console.error('Lexical error:', error);
   748→  },
   749→});
   750→
   751→/**
   752→ * Notes Editor Props
   753→ */
   754→interface NotesEditorProps {
   755→  noteId: string;
