   757→}
   758→
   759→/**
   760→ * Tags Input Component
   761→ * Simple tag management with pills
   762→ */
   763→const TagsInput: React.FC<{ noteId: string; tags: string[] }> = ({ noteId, tags }) => {
   764→  const addTag = useNotesStore((state) => state.addTag);
   765→  const removeTag = useNotesStore((state) => state.removeTag);
   766→
   767→  const handleAddTag = (tag: string) => {
   768→    addTag(noteId, tag);
   769→  };
   770→
   771→  const handleRemoveTag = (tag: string) => {
   772→    removeTag(noteId, tag);
   773→  };
   774→
   775→  return (
   776→    <div className="mt-3">
   777→      <TagPicker
   778→        selectedTags={tags}
   779→        onAddTag={handleAddTag}
