   781→        maxTags={NOTE_CONSTANTS.MAX_TAGS}
   782→      />
   783→    </div>
   784→  );
   785→};
   786→
   787→/**
   788→ * Custom Fields Section Component
   789→ * Renders custom fields defined in settings for notes
   790→ */
   791→const NoteCustomFields: React.FC<{ noteId: string; note: ReturnType<typeof useNotesStore.getState>['notes'][number] }> = ({ noteId, note }) => {
   792→  const { customFieldDefinitions } = useSettingsStore();
   793→  const noteFields = customFieldDefinitions.notes;
   794→
   795→  if (noteFields.length === 0) return null;
   796→
   797→  return (
   798→    <div className="mt-4 space-y-3">
   799→      <div className="text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary">
   800→        Custom Fields
   801→      </div>
   802→      {noteFields.map((field) => {
   803→        const currentValue = note.customFields?.[field.id];
   804→
   805→        return (
   806→          <div key={field.id}>
   807→            <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
