   815→                {field.description}
   816→              </p>
   817→            )}
   818→            <CustomFieldEditor
   819→              field={field}
   820→              value={currentValue}
   821→              onChange={(value) => {
   822→                const updatedCustomFields = {
   823→                  ...note.customFields,
   824→                  [field.id]: value,
   825→                };
   826→                useNotesStore.getState().updateNote(noteId, { customFields: updatedCustomFields });
   827→              }}
   828→            />
   829→          </div>
   830→        );
   831→      })}
   832→    </div>
