   836→/**
   837→ * Notes Editor Component
   838→ */
   839→export const NotesEditor: React.FC<NotesEditorProps> = ({ noteId, blockId }) => {
   840→  const note = useNotesStore((state) => state.getNote(noteId));
   841→  const notes = useNotesStore((state) => state.notes);
   842→  const notesArray = useMemo(() => Object.values(notes), [notes]);
   843→  const [wordCount, setWordCount] = useState(0);
   844→  const [charCount, setCharCount] = useState(0);
   845→  const [viewMode, setViewMode] = useState<ViewMode>('edit');
   846→
   847→  // Keyboard shortcut for toggling view mode (Cmd+E)
   848→  useEffect(() => {
   849→    const handleKeyDown = (e: KeyboardEvent) => {
   850→      if ((e.metaKey || e.ctrlKey) && e.key === 'e') {
   851→        e.preventDefault();
   852→        setViewMode((prev) => (prev === 'edit' ? 'preview' : 'edit'));
   853→      }
   854→    };
   855→    window.addEventListener('keydown', handleKeyDown);
   856→    return () => window.removeEventListener('keydown', handleKeyDown);
   857→  }, []);
   858→
   859→  // Memoize editor config to prevent Lexical re-initialization
   860→  // Only recreate when noteId changes, not when content changes
   861→  const editorConfig = useMemo(
   862→    () => getEditorConfig(note?.content),
   863→    [noteId] // Key on noteId only, not note.content
   864→  );
   865→
   866→  const handleWordCountUpdate = useCallback((words: number, chars: number) => {
