   894→          placeholder="Untitled Note"
   895→          className="w-full text-3xl font-bold bg-transparent border-none outline-none text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary"
   896→        />
   897→        <TagsInput noteId={noteId} tags={note.tags} />
   898→
   899→        {/* Custom Fields (P2 #3) */}
   900→        <NoteCustomFields noteId={noteId} note={note} />
   901→      </div>
   902→
   903→      {/* Lexical Editor */}
   904→      <LexicalComposer key={noteId} initialConfig={editorConfig}>
   905→        <div className="flex-1 flex flex-col relative overflow-hidden shadow-card">
   906→          {/* Toolbar */}
   907→          <div className="flex-shrink-0">
   908→            <EditorToolbar
   909→              wordCount={wordCount}
   910→              charCount={charCount}
