   913→              onViewModeChange={setViewMode}
   914→            />
   915→          </div>
   916→
   917→          {/* Editor Content */}
   918→          <div className="flex-1 overflow-y-auto p-4">
   919→            <div className={`relative h-full border rounded-lg p-6 bg-surface-light dark:bg-surface-dark ${
   920→              viewMode === 'preview'
   921→                ? 'border-accent-cyan/30 dark:border-accent-magenta/30'
