   947→            <ReadOnlyPlugin isReadOnly={viewMode === 'preview'} />
   948→            <HistoryPlugin />
   949→            <ListPlugin />
   950→            <TablePlugin />
   951→            <MarkdownShortcutPlugin transformers={TRANSFORMERS} />
   952→            <AutoLinkPlugin matchers={MATCHERS} />
   953→            <KeyboardShortcutsPlugin />
   954→            <WordCountPlugin onUpdate={handleWordCountUpdate} />
   955→            {viewMode === 'edit' && <SlashCommandPlugin />}
