        {/* Custom Fields (P2 #3) */}
        <NoteCustomFields noteId={noteId} note={note} />
      </div>

      {/* Lexical Editor */}
      <LexicalComposer key={noteId} initialConfig={editorConfig}>
        <div className="flex-1 flex flex-col relative overflow-hidden shadow-card">
          {/* Toolbar */}
          <div className="flex-shrink-0">
            <EditorToolbar
              wordCount={wordCount}
              charCount={charCount}
