              {/* Preview mode indicator */}
              {viewMode === 'preview' && (
                <div className="absolute top-2 right-2 px-2 py-0.5 text-xs bg-accent-cyan/10 text-accent-cyan dark:bg-accent-magenta/10 dark:text-accent-magenta rounded">
                  Preview Mode
