              <RichTextPlugin
                contentEditable={
                  <ContentEditable
                    className={`editor-content outline-none w-full h-full text-text-light-primary dark:text-text-dark-primary text-base ${
                      viewMode === 'preview' ? 'cursor-default select-text' : ''
