   504→/**
   505→ * Note List Item Component
   506→ */
   507→const NoteListItem: React.FC<{
   508→  note: Note;
   509→  isActive: boolean;
   510→  isSelectionMode?: boolean;
   511→  isSelected?: boolean;
   512→  onToggleSelection?: (id: string) => void;
   513→}> = ({
   514→  note,
   515→  isActive,
   516→  isSelectionMode = false,
   517→  isSelected = false,
   518→  onToggleSelection,
   519→}) => {
   520→  const setActiveNote = useNotesStore((state) => state.setActiveNote);
   521→  const deleteNote = useNotesStore((state) => state.deleteNote);
   522→  const togglePin = useNotesStore((state) => state.togglePin);
   523→  const toggleFavorite = useNotesStore((state) => state.toggleFavorite);
   524→  const tagColors = useSettingsStore((state) => state.tagColors);
   525→  const [showDeleteDialog, setShowDeleteDialog] = useState(false);
   526→  const [isExporting, setIsExporting] = useState(false);
   527→  const [exportSuccess, setExportSuccess] = useState<string | null>(null);
   528→
   529→  // Handle PDF export with loading state
   530→  const handlePDFExport = async (e: React.MouseEvent) => {
   531→    e.stopPropagation();
   532→    setIsExporting(true);
   533→    try {
   534→      await exportNoteToPDF(note, (filename) => {
   535→        setExportSuccess(filename);
   536→        setTimeout(() => setExportSuccess(null), 3000); // Clear after 3s
   537→      });
   538→    } catch (error) {
   539→      log.error('PDF export failed', { error });
   540→    } finally {
   541→      setIsExporting(false);
   542→    }
   543→  };
   544→
   545→  // Format date
   546→  const formatDate = (date: Date) => {
   547→    const now = new Date();
   548→    const diff = now.getTime() - new Date(date).getTime();
   549→    const days = Math.floor(diff / (1000 * 60 * 60 * 24));
   550→
   551→    if (days === 0) return 'Today';
   552→    if (days === 1) return 'Yesterday';
   553→    if (days < 7) return `${days} days ago`;
   554→    return new Date(date).toLocaleDateString();
   555→  };
   556→
   557→  // First line of content
   558→  const preview = note.contentText.split('\n')[0] || 'No content';
   559→
   560→  return (
   561→    <div
   562→      className={`group relative p-4 rounded-lg cursor-pointer transition-all duration-standard hover:scale-[1.01] ${
   563→        isActive
   564→          ? 'bg-accent-cyan bg-opacity-10 dark:bg-accent-magenta dark:bg-opacity-10 border-l-4 border-accent-cyan dark:border-accent-magenta shadow-sm'
   565→          : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated border-l-4 border-transparent hover:shadow-sm'
   566→      }`}
   567→      onClick={() => setActiveNote(note.id)}
   568→    >
   569→      {/* Export Success Notification */}
   570→      {exportSuccess && (
   571→        <div className="absolute -top-8 left-0 right-0 bg-accent-green text-white text-xs py-1 px-2 rounded shadow-lg z-10 text-center flex items-center justify-center gap-1">
   572→          <Check className="w-3 h-3" />
   573→          Exported: {exportSuccess}
   574→        </div>
   575→      )}
   576→
   577→      {/* Main layout: Vertical actions on left + Content on right */}
   578→      <div className="flex items-start gap-2">
   579→        {/* Vertical action column - appears on left side on hover */}
   580→        <div className="flex flex-col gap-1 opacity-0 group-hover:opacity-100 transition-opacity duration-200 shrink-0 w-6">
   581→          <button
   582→            onClick={(e) => {
   583→              e.stopPropagation();
   584→              exportNoteToMarkdown(note);
   585→            }}
   586→            className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-all duration-150 hover:scale-110"
   587→            title="Export to Markdown"
   588→            aria-label="Export to Markdown"
   589→          >
   590→            <Download className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
   591→          </button>
   592→          <button
   593→            onClick={handlePDFExport}
   594→            disabled={isExporting}
   595→            className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-all duration-150 hover:scale-110 disabled:opacity-50 disabled:cursor-not-allowed disabled:hover:scale-100"
   596→            title={isExporting ? 'Exporting...' : 'Export to PDF'}
   597→            aria-label={isExporting ? 'Exporting to PDF' : 'Export to PDF'}
   598→          >
   599→            {isExporting ? (
   600→              <Loader2 className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary animate-spin" />
   601→            ) : (
   602→              <FileDown className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
   603→            )}
   604→          </button>
   605→          <button
   606→            onClick={(e) => {
   607→              e.stopPropagation();
   608→              toggleFavorite(note.id);
   609→            }}
   610→            className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-all duration-150 hover:scale-110"
   611→            title={note.isFavorite ? 'Unfavorite' : 'Favorite'}
   612→            aria-label={note.isFavorite ? 'Remove from favorites' : 'Add to favorites'}
   613→          >
   614→            <Star
   615→              className={`w-4 h-4 transition-all duration-200 ${
   616→                note.isFavorite
   617→                  ? 'fill-accent-yellow text-accent-yellow'
   618→                  : 'text-text-light-secondary dark:text-text-dark-secondary'
   619→              }`}
   620→            />
   621→          </button>
   622→          <button
   623→            onClick={(e) => {
   624→              e.stopPropagation();
   625→              togglePin(note.id);
   626→            }}
   627→            className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-all duration-150 hover:scale-110"
   628→            title={note.isPinned ? 'Unpin' : 'Pin'}
   629→            aria-label={note.isPinned ? 'Unpin note' : 'Pin note'}
   630→          >
   631→            <Pin className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
   632→          </button>
   633→          <button
   634→            onClick={(e) => {
   635→              e.stopPropagation();
   636→              setShowDeleteDialog(true);
   637→            }}
   638→            className="p-1 hover:bg-accent-red/10 dark:hover:bg-accent-red/20 rounded text-accent-red transition-all duration-150 hover:scale-110"
   639→            title="Delete"
   640→            aria-label="Delete note"
   641→          >
   642→            <Trash2 className="w-4 h-4" />
   643→          </button>
   644→        </div>
   645→
   646→        {/* Content area - No truncation needed with vertical actions */}
   647→        <div className="flex-1 min-w-0">
   648→          {/* Title row with static indicators */}
   649→          <div className="flex items-start gap-2 mb-1">
   650→            <h4 className="font-medium text-text-light-primary dark:text-text-dark-primary flex-1">
   651→              {note.title}
   652→            </h4>
   653→            {/* Static indicators: always visible when present */}
   654→            <div className="flex items-center gap-1 shrink-0">
   655→              {note.isFavorite && <Star className="w-4 h-4 fill-accent-yellow text-accent-yellow" />}
   656→              {note.isPinned && <Pin className="w-4 h-4 text-accent-yellow" />}
   657→            </div>
   658→          </div>
   659→
   660→          {/* Preview */}
   661→          <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary line-clamp-2 mb-3">
   662→            {preview}
   663→          </p>
   664→
   665→          {/* Tags Display */}
   666→          {note.tags.length > 0 && (
   667→            <div className="flex flex-wrap gap-1 mb-2">
   668→              {note.tags.slice(0, 3).map((tag) => {
   669→                const color = tagColors[tag];
   670→                return (
   671→                  <span
   672→                    key={tag}
   673→                    className={`inline-flex items-center gap-1 px-2 py-0.5 text-xs font-medium rounded ${
   674→                      color
   675→                        ? `bg-${color}/10 text-${color} dark:bg-${color}/20`
   676→                        : 'bg-accent-purple/10 text-accent-purple dark:bg-accent-cyan/10 dark:text-accent-cyan'
   677→                    }`}
   678→                  >
   679→                    <Tag className="w-3 h-3" />
   680→                    {tag}
   681→                  </span>
   682→                );
   683→              })}
   684→              {note.tags.length > 3 && (
   685→                <span className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary px-1">
   686→                  +{note.tags.length - 3} more
   687→                </span>
   688→              )}
   689→            </div>
   690→          )}
   691→
   692→          {/* Meta */}
   693→          <div className="flex items-center justify-between text-xs text-text-light-secondary dark:text-text-dark-secondary">
   694→            <span>{formatDate(note.updatedAt)}</span>
   695→          </div>
   696→        </div>
   697→
   698→        {/* Selection checkbox (if in selection mode) */}
   699→        {isSelectionMode && onToggleSelection && (
   700→          <div className="shrink-0 ml-2" onClick={(e) => e.stopPropagation()}>
   701→            <input
   702→              type="checkbox"
   703→              checked={isSelected}
   704→              onChange={() => onToggleSelection(note.id)}
   705→              className="w-4 h-4 rounded border-border-light dark:border-border-dark cursor-pointer"
   706→              aria-label={`Select note ${note.title}`}
   707→            />
   708→          </div>
   709→        )}
   710→      </div>
   711→
   712→      {/* Delete Confirmation Dialog */}
   713→      {showDeleteDialog && (
   714→        <ConfirmDialog
   715→          isOpen={true}
   716→          onClose={() => setShowDeleteDialog(false)}
   717→          onConfirm={() => {
   718→            deleteNote(note.id);
   719→            setShowDeleteDialog(false);
   720→          }}
   721→          title="Delete Note"
   722→          message={`Are you sure you want to delete "${note.title}"? This action cannot be undone.`}
   723→          variant="danger"
   724→        />
   725→      )}
   726→    </div>
   727→  );
   728→};
