   730→/**
   731→ * Notes List Component
   732→ */
   733→const NotesList: React.FC<{
   734→  activeTags: string[];
   735→  onOpenTemplateLibrary: () => void;
   736→  onOpenExportModal: () => void;
   737→}> = ({ activeTags, onOpenTemplateLibrary, onOpenExportModal }) => {
   738→  const activeFolderId = useFoldersStore((state) => state.activeFolderId);
   739→  // Get raw notes and store config (stable references)
   740→  const notesObj = useNotesStore((state) => state.notes);
   741→  const sortConfig = useNotesStore((state) => state.sortConfig);
   742→  const filter = useNotesStore((state) => state.filter);
   743→  const activeNoteId = useNotesStore((state) => state.activeNoteId);
   744→  const createNote = useNotesStore((state) => state.createNote);
   745→  const bulkAddTag = useNotesStore((state) => state.bulkAddTag);
   746→  const bulkRemoveTag = useNotesStore((state) => state.bulkRemoveTag);
   747→
   748→  // Bulk operations state
   749→  const [selectionMode, setSelectionMode] = useState(false);
   750→  const [selectedNoteIds, setSelectedNoteIds] = useState<Set<string>>(new Set());
   751→  const [bulkTagDialogOpen, setBulkTagDialogOpen] = useState(false);
   752→  const [bulkTagAction, setBulkTagAction] = useState<'add' | 'remove' | null>(null);
   753→  const [bulkTagValue, setBulkTagValue] = useState('');
   754→
   755→  // Bulk operations handlers
   756→  const toggleSelectionMode = () => {
   757→    setSelectionMode(!selectionMode);
   758→    if (selectionMode) {
   759→      setSelectedNoteIds(new Set());
   760→    }
   761→  };
   762→
   763→  const toggleNoteSelection = (noteId: string) => {
   764→    setSelectedNoteIds((prev) => {
   765→      const next = new Set(prev);
   766→      if (next.has(noteId)) {
   767→        next.delete(noteId);
   768→      } else {
   769→        next.add(noteId);
   770→      }
   771→      return next;
   772→    });
   773→  };
   774→
   775→  const selectAll = () => {
   776→    const allIds = notes.map((n) => n.id);
   777→    setSelectedNoteIds(new Set(allIds));
   778→  };
   779→
   780→  const deselectAll = () => {
   781→    setSelectedNoteIds(new Set());
   782→  };
   783→
   784→  const handleBulkAddTag = () => {
   785→    setBulkTagAction('add');
   786→    setBulkTagDialogOpen(true);
   787→  };
   788→
   789→  const handleBulkRemoveTag = () => {
   790→    setBulkTagAction('remove');
   791→    setBulkTagDialogOpen(true);
   792→  };
   793→
   794→  const confirmBulkTagAction = (value: string) => {
   795→    if (!value.trim() || selectedNoteIds.size === 0) return;
   796→
   797→    if (bulkTagAction === 'add') {
   798→      bulkAddTag(Array.from(selectedNoteIds), value.trim());
   799→    } else if (bulkTagAction === 'remove') {
   800→      bulkRemoveTag(Array.from(selectedNoteIds), value.trim());
   801→    }
   802→
   803→    // Clear selection and close dialog
   804→    setBulkTagDialogOpen(false);
   805→    setBulkTagValue('');
   806→    setSelectedNoteIds(new Set());
   807→    setSelectionMode(false);
   808→  };
   809→
   810→  // Compute filtered/sorted notes with useMemo
   811→  const notes = useMemo(() => {
   812→    // Filter by folder
   813→    // If activeFolderId is null, show ALL notes (not just notes with null folderId)
   814→    let filtered = activeFolderId === null
   815→      ? Object.values(notesObj) // Show all notes when "All Notes" is selected
   816→      : Object.values(notesObj).filter((note) => note.folderId === activeFolderId);
   817→
   818→    // Filter by tags (AND logic - note must have ALL selected tags or their children)
   819→    if (activeTags.length > 0) {
   820→      filtered = filtered.filter((note) =>
   821→        activeTags.every((filterTag) =>
   822→          note.tags.some((noteTag) => tagMatchesFilter(noteTag, filterTag))
   823→        )
   824→      );
   825→    }
   826→
   827→    // Apply filter (archived, pinned, favorites, etc.)
   828→    switch (filter) {
   829→      case 'favorites':
   830→        filtered = filtered.filter((note) => note.isFavorite);
   831→        break;
   832→      case 'pinned':
   833→        filtered = filtered.filter((note) => note.isPinned);
   834→        break;
   835→      case 'archived':
   836→        filtered = filtered.filter((note) => note.isArchived);
   837→        break;
   838→      case 'unarchived':
   839→        filtered = filtered.filter((note) => !note.isArchived);
   840→        break;
   841→    }
   842→
   843→    // Sort notes
   844→    const sorted = [...filtered].sort((a, b) => {
   845→      let comparison = 0;
   846→      switch (sortConfig.field) {
   847→        case 'title':
   848→          comparison = a.title.localeCompare(b.title);
   849→          break;
   850→        case 'createdAt':
   851→          comparison = a.createdAt.getTime() - b.createdAt.getTime();
   852→          break;
   853→        case 'updatedAt':
   854→          comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
   855→          break;
   856→      }
   857→      return sortConfig.order === 'asc' ? comparison : -comparison;
   858→    });
   859→
   860→    // Always pin pinned notes to top
   861→    return sorted.sort((a, b) => {
   862→      if (a.isPinned && !b.isPinned) return -1;
   863→      if (!a.isPinned && b.isPinned) return 1;
   864→      return 0;
   865→    });
   866→  }, [notesObj, activeFolderId, sortConfig, filter, activeTags]);
   867→
   868→  return (
   869→    <div className="flex-1 overflow-y-auto">
   870→      <div className="bento-card p-4 m-3">
   871→        {/* Notes header */}
   872→        <div className="flex items-center justify-between mb-4">
   873→          <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
   874→            Notes ({notes.length})
   875→          </h3>
   876→          <div className="flex items-center gap-2">
   877→            <button
   878→              onClick={onOpenExportModal}
   879→              className="px-3 py-1.5 rounded-lg text-sm font-medium border border-border-light dark:border-border-dark text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-all duration-200 flex items-center gap-1"
   880→              title="Export notes (Cmd+Shift+E)"
   881→            >
   882→              <FileDown className="w-4 h-4" />
   883→              Export
   884→            </button>
   885→            <button
   886→              onClick={toggleSelectionMode}
   887→              className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-all duration-200 ${
   888→                selectionMode
   889→                  ? 'bg-accent-cyan/20 dark:bg-accent-magenta/20 text-accent-cyan dark:text-accent-magenta'
   890→                  : 'border border-border-light dark:border-border-dark text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   891→              }`}
   892→            >
   893→              {selectionMode ? 'Cancel Selection' : 'Select Notes'}
   894→            </button>
   895→            <button
   896→              onClick={onOpenTemplateLibrary}
   897→              className="px-3 py-1.5 bg-accent-purple text-white rounded-lg hover:bg-accent-purple-hover transition-all duration-200 text-sm font-medium flex items-center gap-1"
   898→              title="Create note from template"
   899→            >
   900→              <Sparkles className="w-4 h-4" />
   901→              From Template
   902→            </button>
   903→            <button
   904→              onClick={() => createNote({ folderId: activeFolderId })}
   905→              className="px-3 py-1.5 bg-gradient-button-primary text-white rounded-lg hover:shadow-glow-magenta transition-all duration-200 text-sm font-medium"
   906→            >
   907→              + New Note
   908→            </button>
   909→          </div>
   910→        </div>
   911→
   912→        {/* Bulk Operations Toolbar */}
   913→        {selectionMode && selectedNoteIds.size > 0 && (
   914→          <div className="mb-4 p-3 rounded-lg bg-accent-blue/10 dark:bg-accent-blue/20 border border-accent-blue/30">
   915→            <div className="flex items-center justify-between">
   916→              <span className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
   917→                {selectedNoteIds.size} note{selectedNoteIds.size !== 1 ? 's' : ''} selected
   918→              </span>
   919→              <div className="flex items-center gap-2">
   920→                <button
   921→                  onClick={selectAll}
   922→                  className="px-2 py-1 text-xs font-medium rounded border border-border-light dark:border-border-dark hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors text-text-light-secondary dark:text-text-dark-secondary"
   923→                >
   924→                  Select All
   925→                </button>
   926→                <button
   927→                  onClick={deselectAll}
   928→                  className="px-2 py-1 text-xs font-medium rounded border border-border-light dark:border-border-dark hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors text-text-light-secondary dark:text-text-dark-secondary"
   929→                >
   930→                  Deselect All
   931→                </button>
   932→                <button
   933→                  onClick={handleBulkAddTag}
   934→                  className="px-3 py-1 text-xs font-medium rounded bg-accent-blue text-white hover:bg-accent-blue-hover transition-colors"
   935→                >
   936→                  Add Tag
   937→                </button>
   938→                <button
   939→                  onClick={handleBulkRemoveTag}
   940→                  className="px-3 py-1 text-xs font-medium rounded bg-accent-red/20 text-accent-red hover:bg-accent-red/30 transition-colors"
   941→                >
   942→                  Remove Tag
   943→                </button>
   944→              </div>
   945→            </div>
   946→          </div>
   947→        )}
   948→
   949→      {/* Notes list */}
   950→      <div className="space-y-3">
   951→        {notes.map((note) => (
   952→          <NoteListItem
   953→            key={note.id}
   954→            note={note}
   955→            isActive={note.id === activeNoteId}
   956→            isSelectionMode={selectionMode}
   957→            isSelected={selectedNoteIds.has(note.id)}
   958→            onToggleSelection={toggleNoteSelection}
   959→          />
   960→        ))}
   961→      </div>
   962→
   963→      {/* Empty state */}
   964→      {notes.length === 0 && (
   965→        <div className="text-center py-16 animate-fade-in">
   966→          <div className="flex justify-center mb-6">
   967→            <div className="p-6 bg-gradient-to-br from-accent-magenta/10 to-accent-cyan/10 dark:from-accent-cyan/10 dark:to-accent-magenta/10 rounded-2xl">
   968→              <FileText className="w-16 h-16 text-accent-cyan dark:text-accent-magenta" />
   969→            </div>
   970→          </div>
   971→          <h3 className="text-2xl font-bold text-text-light-primary dark:text-text-dark-primary mb-3">
   972→            {activeTags.length > 0 ? 'No notes match these tags' : 'No notes in this folder'}
   973→          </h3>
   974→          <p className="text-text-light-secondary dark:text-text-dark-secondary mb-2 max-w-sm mx-auto">
   975→            {activeTags.length > 0
   976→              ? 'Try removing some tags or create a new note'
   977→              : 'Start capturing your thoughts, ideas, and knowledge'}
   978→          </p>
   979→          <p className="text-sm text-text-light-tertiary dark:text-text-dark-tertiary mb-6">
   980→            Tip: Use <kbd className="px-2 py-1 bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded text-xs font-mono">Cmd+N</kbd> to create notes quickly
   981→          </p>
   982→          <button
   983→            onClick={() => createNote({ folderId: activeFolderId })}
   984→            className="px-6 py-3 bg-gradient-button-primary text-white rounded-lg hover:shadow-glow-magenta transition-all duration-standard font-medium inline-flex items-center gap-2"
   985→          >
   986→            <FileText className="w-5 h-5" />
   987→            Create Your First Note
   988→          </button>
   989→        </div>
   990→      )}
   991→      </div>
   992→
   993→      {/* Bulk Tag Dialog */}
   994→      {bulkTagDialogOpen && (
   995→        <PromptDialog
   996→          isOpen={true}
   997→          onClose={() => {
   998→            setBulkTagDialogOpen(false);
   999→            setBulkTagValue('');
  1000→          }}
  1001→          onConfirm={confirmBulkTagAction}
  1002→          title={bulkTagAction === 'add' ? 'Add Tag to Selected Notes' : 'Remove Tag from Selected Notes'}
  1003→          message={
  1004→            bulkTagAction === 'add'
  1005→              ? `Enter tag name to add to ${selectedNoteIds.size} note${selectedNoteIds.size !== 1 ? 's' : ''}:`
  1006→              : `Enter tag name to remove from ${selectedNoteIds.size} note${selectedNoteIds.size !== 1 ? 's' : ''}:`
  1007→          }
  1008→          defaultValue={bulkTagValue}
  1009→          placeholder="Tag name"
  1010→          confirmText={bulkTagAction === 'add' ? 'Add Tag' : 'Remove Tag'}
  1011→        />
  1012→      )}
  1013→    </div>
  1014→  );
  1015→};
  1016→
  1017→/**
  1018→ * Notes Page Component
  1019→ * Phase 5: Updated with TabNavigation for tabs (Notes, Daily Notes, Graph)
  1020→ */
  1021→export const Notes: React.FC = () => {
  1022→  const activeNoteId = useNotesStore((state) => state.activeNoteId);
  1023→  const getOrCreateDailyNote = useNotesStore((state) => state.getOrCreateDailyNote);
  1024→  const dailyNotesEnabled = useSettingsStore((state) => state.dailyNotes.enabled);
  1025→  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
  1026→  const [sidebarWidth, setSidebarWidth] = useState(320);
  1027→  const [isResizing, setIsResizing] = useState(false);
  1028→  const sidebarRef = useRef<HTMLDivElement>(null);
  1029→  const [searchParams, setSearchParams] = useSearchParams();
  1030→  const navigate = useNavigate();
  1031→  const [blockId, setBlockId] = useState<string | undefined>();
  1032→
  1033→  // Phase 5: Tab state management
  1034→  const getTabFromUrl = (): NotesTabType => {
  1035→    const tab = searchParams.get('tab');
  1036→    if (tab && VALID_TABS.includes(tab as NotesTabType)) {
  1037→      return tab as NotesTabType;
  1038→    }
  1039→    // Legacy support: ?daily=true maps to daily tab
  1040→    if (searchParams.get('daily') === 'true') {
  1041→      return 'daily';
  1042→    }
  1043→    return 'notes'; // Default tab
  1044→  };
  1045→
  1046→  const [activeTab, setActiveTab] = useState<NotesTabType>(getTabFromUrl);
  1047→
  1048→  // Update tab when URL changes
  1049→  useEffect(() => {
  1050→    const newTab = getTabFromUrl();
  1051→    if (newTab !== activeTab) {
  1052→      setActiveTab(newTab);
  1053→    }
  1054→  }, [searchParams]);
  1055→
  1056→  // Update URL when tab changes
  1057→  const handleTabChange = (tab: NotesTabType) => {
  1058→    setActiveTab(tab);
  1059→    navigate(`/notes?tab=${tab}`, { replace: true });
  1060→  };
  1061→
  1062→  // Tag filtering state
  1063→  const [activeTags, setActiveTags] = useState<string[]>([]);
  1064→  const [showTagManager, setShowTagManager] = useState(false);
  1065→
  1066→  // Template Library state
  1067→  const [showTemplateLibrary, setShowTemplateLibrary] = useState(false);
  1068→  const [showTitlePrompt, setShowTitlePrompt] = useState(false);
  1069→  const [selectedTemplate, setSelectedTemplate] = useState<NoteTemplate | null>(null);
  1070→  const [titleInput, setTitleInput] = useState('');
  1071→
  1072→  // Export Modal state
  1073→  const [showExportModal, setShowExportModal] = useState(false);
  1074→
  1075→  // Get store actions
  1076→  const createNote = useNotesStore((state) => state.createNote);
  1077→  const activeFolderId = useFoldersStore((state) => state.activeFolderId);
  1078→
  1079→  const handleAddTag = (tag: string) => {
  1080→    if (!activeTags.includes(tag)) {
  1081→      setActiveTags([...activeTags, tag]);
  1082→    }
  1083→  };
  1084→
  1085→  const handleRemoveTag = (tag: string) => {
  1086→    setActiveTags(activeTags.filter((t) => t !== tag));
  1087→  };
  1088→
  1089→  const handleClearAllTags = () => {
  1090→    setActiveTags([]);
  1091→  };
  1092→
  1093→  // Template selection handlers
  1094→  const handleSelectTemplate = (template: NoteTemplate) => {
  1095→    // Check if template contains {title} variable
  1096→    const variables = extractTemplateVariables(template.description);
  1097→    if (variables.includes('title')) {
  1098→      // Prompt user for title
  1099→      setSelectedTemplate(template);
  1100→      setTitleInput('');
  1101→      setShowTitlePrompt(true);
  1102→      setShowTemplateLibrary(false);
  1103→    } else {
  1104→      // Create note immediately with variable substitution
  1105→      createNoteFromTemplate(template);
  1106→    }
  1107→  };
  1108→
  1109→  const createNoteFromTemplate = (template: NoteTemplate, customTitle?: string) => {
  1110→    // Substitute template variables
  1111→    const context = {
  1112→      title: customTitle,
  1113→      userName: 'User', // Could be fetched from settings in future
  1114→    };
  1115→    const processedContent = substituteTemplateVariables(template.description, context);
  1116→
  1117→    // Create note with template content and tags
  1118→    const newNote = createNote({
  1119→      folderId: activeFolderId,
  1120→      title: customTitle || template.name,
  1121→      contentText: processedContent,
  1122→      tags: template.defaultTags || [],
  1123→      icon: template.icon,
  1124→    });
  1125→
  1126→    log.info('Created note from template', {
  1127→      templateId: template.id,
  1128→      noteId: newNote.id,
  1129→      title: newNote.title,
  1130→    });
  1131→  };
  1132→
  1133→  const handleConfirmTitle = (title: string) => {
  1134→    if (selectedTemplate && title.trim()) {
  1135→      createNoteFromTemplate(selectedTemplate, title.trim());
  1136→      setShowTitlePrompt(false);
  1137→      setSelectedTemplate(null);
  1138→      setTitleInput('');
  1139→    }
  1140→  };
  1141→
  1142→  const handleCancelTitle = () => {
  1143→    setShowTitlePrompt(false);
  1144→    setSelectedTemplate(null);
  1145→    setTitleInput('');
  1146→  };
  1147→
  1148→  useEffect(() => {
  1149→    document.title = 'Notes - Neuman Brain';
  1150→    log.debug('Notes page loaded');
  1151→
  1152→    // Keyboard shortcut for export (Cmd/Ctrl+Shift+E)
  1153→    const handleKeyDown = (e: KeyboardEvent) => {
  1154→      if ((e.metaKey || e.ctrlKey) && e.shiftKey && e.key === 'E') {
  1155→        e.preventDefault();
  1156→        setShowExportModal(true);
  1157→      }
  1158→    };
  1159→
  1160→    window.addEventListener('keydown', handleKeyDown);
  1161→    return () => window.removeEventListener('keydown', handleKeyDown);
  1162→  }, []);
  1163→
  1164→  // Handle ?daily=true query parameter to open today's daily note
  1165→  useEffect(() => {
  1166→    if (searchParams.get('daily') === 'true' && dailyNotesEnabled) {
  1167→      const today = new Date();
  1168→      getOrCreateDailyNote(today); // Auto-selects the note by setting activeNoteId
  1169→      // Remove the query parameter after handling it
  1170→      searchParams.delete('daily');
  1171→      setSearchParams(searchParams, { replace: true });
  1172→    }
  1173→  }, [searchParams, dailyNotesEnabled, getOrCreateDailyNote, setSearchParams]);
  1174→
  1175→  // Extract block ID from URL hash (#block-id)
  1176→  useEffect(() => {
  1177→    const handleHashChange = () => {
  1178→      const hash = window.location.hash;
  1179→      if (hash && hash.startsWith('#')) {
  1180→        const id = hash.substring(1); // Remove # prefix
  1181→        setBlockId(id);
  1182→      } else {
  1183→        setBlockId(undefined);
  1184→      }
  1185→    };
  1186→
  1187→    // Set initial block ID
  1188→    handleHashChange();
  1189→
  1190→    // Listen for hash changes
  1191→    window.addEventListener('hashchange', handleHashChange);
  1192→    return () => window.removeEventListener('hashchange', handleHashChange);
  1193→  }, []);
  1194→
  1195→  // Handle sidebar resize
  1196→  const handleMouseDown = (e: React.MouseEvent) => {
  1197→    e.preventDefault();
  1198→    setIsResizing(true);
  1199→  };
  1200→
  1201→  useEffect(() => {
  1202→    const handleMouseMove = (e: MouseEvent) => {
  1203→      if (!isResizing) return;
  1204→      const newWidth = Math.max(200, Math.min(500, e.clientX - 72)); // 72px is sidebar offset
  1205→      setSidebarWidth(newWidth);
  1206→    };
  1207→
  1208→    const handleMouseUp = () => {
  1209→      setIsResizing(false);
  1210→    };
  1211→
  1212→    if (isResizing) {
  1213→      document.addEventListener('mousemove', handleMouseMove);
  1214→      document.addEventListener('mouseup', handleMouseUp);
  1215→      document.body.style.cursor = 'ew-resize';
  1216→      document.body.style.userSelect = 'none';
  1217→    }
  1218→
  1219→    return () => {
  1220→      document.removeEventListener('mousemove', handleMouseMove);
  1221→      document.removeEventListener('mouseup', handleMouseUp);
  1222→      document.body.style.cursor = '';
  1223→      document.body.style.userSelect = '';
  1224→    };
  1225→  }, [isResizing]);
  1226→
  1227→  return (
  1228→    <PageContent page="notes">
  1229→      {/* Phase 5: Tab Navigation */}
  1230→      <TabNavigation
  1231→        tabs={NOTES_TABS}
  1232→        activeTab={activeTab}
  1233→        onTabChange={(tabId) => handleTabChange(tabId as NotesTabType)}
  1234→        ariaLabel="Notes navigation"
  1235→      />
  1236→
  1237→      {/* Tab Content */}
  1238→      <div
  1239→        role="tabpanel"
  1240→        id={`tabpanel-${activeTab}`}
  1241→        aria-labelledby={`tab-${activeTab}`}
  1242→        className="min-h-[600px]"
  1243→      >
  1244→        {/* Graph Tab - Lazy loaded GraphView */}
  1245→        {activeTab === 'graph' && (
  1246→          <Suspense fallback={<GraphViewLoader />}>
  1247→            <GraphView />
  1248→          </Suspense>
  1249→        )}
  1250→
  1251→        {/* Daily Notes Tab - Show Daily Notes Calendar */}
  1252→        {activeTab === 'daily' && (
  1253→          <div className="h-[calc(100vh-340px)] overflow-auto p-6">
  1254→            <DailyNotesCalendar />
  1255→          </div>
  1256→        )}
  1257→
  1258→        {/* Notes Tab - Main Notes View */}
  1259→        {activeTab === 'notes' && (
  1260→          <div className="h-[calc(100vh-340px)] flex relative">
  1261→        {/* Left Sidebar - Folders + Notes List */}
  1262→        <AnimatePresence>
  1263→        {!isSidebarCollapsed && (
  1264→          <motion.div
  1265→            ref={sidebarRef}
  1266→            initial={{ width: 0, opacity: 0 }}
  1267→            animate={{ width: sidebarWidth, opacity: 1 }}
  1268→            exit={{ width: 0, opacity: 0 }}
  1269→            transition={{ duration: 0.2 }}
  1270→            className="flex-shrink-0 border-r border-border-light dark:border-border-dark bg-transparent flex flex-col relative"
  1271→            style={{ width: sidebarWidth }}
  1272→          >
  1273→            <FolderSidebar
  1274→              activeTags={activeTags}
  1275→              onAddTag={handleAddTag}
  1276→              onRemoveTag={handleRemoveTag}
  1277→              onClearAllTags={handleClearAllTags}
  1278→              onOpenTagManager={() => setShowTagManager(true)}
  1279→            />
  1280→            <NotesList
  1281→              activeTags={activeTags}
  1282→              onOpenTemplateLibrary={() => setShowTemplateLibrary(true)}
  1283→              onOpenExportModal={() => setShowExportModal(true)}
  1284→            />
  1285→
  1286→            {/* Collapse button - inside sidebar at top right */}
  1287→            <button
  1288→              onClick={() => setIsSidebarCollapsed(true)}
  1289→              className="absolute top-4 right-2 z-20 p-1.5 bg-surface-light dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button hover:bg-surface-light-elevated dark:hover:bg-surface-dark transition-all duration-200"
  1290→              title="Collapse Sidebar"
  1291→            >
  1292→              <svg className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" fill="none" stroke="currentColor" viewBox="0 0 24 24">
  1293→                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 19l-7-7 7-7m8 14l-7-7 7-7" />
  1294→              </svg>
  1295→            </button>
  1296→
  1297→            {/* Resize handle */}
  1298→            <div
  1299→              onMouseDown={handleMouseDown}
  1300→              className={`absolute right-0 top-0 bottom-0 w-1 cursor-ew-resize hover:bg-accent-blue/50 transition-colors ${isResizing ? 'bg-accent-blue' : ''}`}
  1301→              title="Drag to resize"
  1302→            />
  1303→          </motion.div>
  1304→        )}
  1305→      </AnimatePresence>
  1306→
  1307→        {/* Sidebar expand button - shown when collapsed */}
  1308→        {isSidebarCollapsed && (
  1309→          <button
  1310→            onClick={() => setIsSidebarCollapsed(false)}
  1311→            className="flex-shrink-0 p-2 bg-surface-light dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-r-lg hover:bg-surface-light-elevated dark:hover:bg-surface-dark transition-all duration-200 self-start mt-4 ml-2"
  1312→            title="Expand Sidebar"
  1313→          >
  1314→            <svg className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" fill="none" stroke="currentColor" viewBox="0 0 24 24">
  1315→              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 5l7 7-7 7M5 5l7 7-7 7" />
  1316→            </svg>
  1317→          </button>
  1318→        )}
  1319→
  1320→        {/* Spacer between sidebar and editor */}
  1321→        {!isSidebarCollapsed && <div className="w-4 flex-shrink-0" />}
  1322→
  1323→      {/* Center - Editor */}
  1324→      <div className="flex-1 overflow-hidden flex flex-col">
  1325→        {/* Main Content Area */}
  1326→        <div className="flex-1 overflow-hidden border border-border-light dark:border-border-dark rounded-lg">
  1327→          {activeNoteId ? (
  1328→            <NotesEditor noteId={activeNoteId} blockId={blockId} />
  1329→          ) : (
  1330→            <NotesEditorEmpty />
  1331→          )}
  1332→        </div>
  1333→      </div>
  1334→
  1335→      {/* Right Sidebar - Metadata Panel (Future Feature)
  1336→          Will show: creation date, modified date, word count, tags, backlinks
  1337→          See feature_map.md Section 1.4 for planning */}
  1338→    </div>
  1339→        )}
  1340→      </div>
  1341→
  1342→      {/* Tag Manager Modal */}
  1343→      <TagManager
  1344→        isOpen={showTagManager}
  1345→        onClose={() => setShowTagManager(false)}
  1346→      />
  1347→
  1348→      {/* Template Library Modal */}
  1349→      <TemplateLibrary
  1350→        isOpen={showTemplateLibrary}
  1351→        onClose={() => setShowTemplateLibrary(false)}
  1352→        onSelect={handleSelectTemplate}
  1353→      />
  1354→
  1355→      {/* Title Prompt Modal */}
  1356→      {showTitlePrompt && selectedTemplate && (
  1357→        <PromptDialog
  1358→          isOpen={true}
  1359→          onClose={handleCancelTitle}
  1360→          onConfirm={handleConfirmTitle}
  1361→          title="Enter Note Title"
  1362→          message={`Create a note from template "${selectedTemplate.name}". Please enter a title:`}
  1363→          defaultValue={titleInput}
  1364→          placeholder="Note title"
  1365→          confirmText="Create Note"
  1366→        />
  1367→      )}
  1368→
  1369→      {/* Export Notes Modal */}
  1370→      <ExportNotesModal
  1371→        isOpen={showExportModal}
  1372→        onClose={() => setShowExportModal(false)}
